        <article class="setup-card">
          <h3>Attempts & Completion</h3>
          <div class="input-inline">
            <label>Attempts allowed</label>
            <input type="number" min="1" [(ngModel)]="quizForm.maxAttempts" name="maxAttemptsSettings">
          </div>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.unlockAfterVideos" name="unlockAfterVideosSettings">
            Lock until mandatory videos complete
          </label>
        </article>

        <article class="setup-card">
          <h3>Evaluation & Feedback</h3>
          <div class="input-inline">
            <label>Pass mark (%)</label>
            <input type="number" min="0" max="100" [(ngModel)]="quizForm.passingMark" name="passingMarkSettings">
          </div>
          <label class="check-row">
            <input type="checkbox" [(ngModel)]="quizForm.showResultImmediately" name="showResultImmediatelySettings">
            Release result immediately
          </label>
          @if (!quizForm.showResultImmediately) {
            <div class="input-inline">
              <label>Result release date</label>
              <input type="date" [(ngModel)]="quizForm.resultReleaseDate" name="resultReleaseDateSettings">
            </div>
            <div class="input-inline">
              <label>Result release time</label>
              <input type="time" [(ngModel)]="quizForm.resultReleaseTime" name="resultReleaseTimeSettings">
            </div>
          }
          <p class="side-detail">Selected question count: {{ selectedQuestionIds.length }}</p>
        </article>

        <article class="setup-card">
          <h3>Auto-Select Questions</h3>
          <div class="input-inline">
            <label>Question count (when nothing selected)</label>
            <input type="number" min="1" [(ngModel)]="quizForm.autoSelectCount" name="autoSelectCountSettings">
